// Get all distributors
const allDistributors = $input.all().map(item => item.json);

// Get yesterday's date range
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);
yesterday.setHours(0, 0, 0, 0);

const today = new Date(now);
today.setHours(0, 0, 0, 0);

// Filter for yesterday's signups
const yesterdaySignups = allDistributors.filter(d => {
  const createdAt = new Date(d.created_at);
  return createdAt >= yesterday && createdAt < today;
});

// Format for output
return yesterdaySignups.map(signup => ({
  json: signup
}));

const signups = $input.all();

if (!signups || signups.length === 0) {
  return [{
    json: {
      subject: 'Daily Enrollment Report - No new signups',
      html: '<h2>No new signups yesterday</h2>',
      to: 'admin@theapexway.net'
    }
  }];
}

const rows = signups.map(item => {
  const signup = item.json;
  const date = new Date(signup.created_at);
  return `
    <tr>
      <td style="padding:8px;border:1px solid #ddd">${date.toLocaleString()}</td>
      <td style="padding:8px;border:1px solid #ddd">${signup.first_name} ${signup.last_name}</td>
      <td style="padding:8px;border:1px solid #ddd">${signup.email}</td>
      <td style="padding:8px;border:1px solid #ddd">${signup.phone || 'N/A'}</td>
      <td style="padding:8px;border:1px solid #ddd">${signup.slug}</td>
    </tr>
  `;
}).join('');

const html = `
<!DOCTYPE html>
<html>
<body style="font-family:Arial,sans-serif;padding:20px">
  <h1 style="color:#2c5aa0">Daily Enrollment Report</h1>
  <p><strong>${signups.length}</strong> new signup${signups.length !== 1 ? 's' : ''} yesterday</p>
  <table style="width:100%;border-collapse:collapse">
    <tr style="background:#f0f0f0">
      <th style="padding:8px;border:1px solid #ddd;text-align:left">Date</th>
      <th style="padding:8px;border:1px solid #ddd;text-align:left">Name</th>
      <th style="padding:8px;border:1px solid #ddd;text-align:left">Email</th>
      <th style="padding:8px;border:1px solid #ddd;text-align:left">Phone</th>
      <th style="padding:8px;border:1px solid #ddd;text-align:left">Slug</th>
    </tr>
    ${rows}
  </table>
</body>
</html>
`;

return [{
  json: {
    subject: `Daily Enrollment Report - ${signups.length} new signup${signups.length !== 1 ? 's' : ''}`,
    html: html,
    to: 'admin@theapexway.net'
  }
}];
